import React, { useEffect, useState } from 'react';
import api from '../utils/api';

type Notif = { id:number; type:'approved'|'rejected'|'pending'; title:string; message:string; created_at:string; };

const statusStyle = (s:string) => {
  const m:any = {
    borrowed: { bg:'rgba(245,158,11,0.12)', color:'#d97706' },
    returned: { bg:'rgba(16,185,129,0.12)', color:'#059669' },
    overdue:  { bg:'rgba(239,68,68,0.12)',  color:'#dc2626' },
    pending:  { bg:'rgba(245,158,11,0.12)', color:'#d97706' },
    approved: { bg:'rgba(16,185,129,0.12)', color:'#059669' },
    rejected: { bg:'rgba(239,68,68,0.12)',  color:'#dc2626' },
  };
  return m[s] || { bg:'rgba(107,114,128,0.12)', color:'#6b7280' };
};

const notifIcon = (type:string) => type==='approved'?'✓':type==='rejected'?'✕':'⏳';
const notifColor = (type:string) => type==='approved'?'#10b981':type==='rejected'?'#ef4444':'#f59e0b';
const notifBg   = (type:string) => type==='approved'?'rgba(16,185,129,0.1)':type==='rejected'?'rgba(239,68,68,0.1)':'rgba(245,158,11,0.1)';

export default function MyBorrows() {
  const [borrows, setBorrows]   = useState<any[]>([]);
  const [requests, setRequests] = useState<any[]>([]);
  const [notifs, setNotifs]     = useState<Notif[]>([]);
  const [trash, setTrash]       = useState<Notif[]>([]);
  const [loading, setLoading]   = useState(true);
  const [tab, setTab] = useState<'requests'|'borrows'|'notifications'|'trash'>('requests');
  const [trashLoaded, setTrashLoaded] = useState(false);

  const loadAll = () => {
    setLoading(true);
    Promise.all([
      api.get('/borrows/my'),
      api.get('/borrows/my-requests'),
      api.get('/borrows/notifications'),
    ]).then(([b,r,n]) => {
      setBorrows(b.data.data||[]);
      setRequests(r.data.data||[]);
      setNotifs(n.data.data||[]);
      setLoading(false);
    }).catch(()=>setLoading(false));
  };

  useEffect(()=>{ loadAll(); }, []);

  const loadTrash = async () => {
    if (trashLoaded) return;
    const { data } = await api.get('/borrows/notifications/trash');
    setTrash(data.data||[]);
    setTrashLoaded(true);
  };

  const softDelete = async (id:number) => {
    await api.delete(`/borrows/notifications/${id}`);
    setNotifs(n=>n.filter(x=>x.id!==id));
    setTrashLoaded(false); // refresh trash next time
  };

  const permDelete = async (id:number) => {
    if (!window.confirm('Permanently delete this notification?')) return;
    await api.delete(`/borrows/notifications/${id}/permanent`);
    setTrash(t=>t.filter(x=>x.id!==id));
  };

  const pendingCount   = requests.filter(r=>r.status==='pending').length;
  const unreadNotifs   = notifs.length;

  const tabs = [
    { key:'requests',      label:'My Requests',    count:pendingCount },
    { key:'borrows',       label:'Borrowed Books',  count:0 },
    { key:'notifications', label:'Notifications',   count:unreadNotifs },
    { key:'trash',         label:'Trash',           count:0 },
  ] as const;

  return (
    <div className="page-enter" style={{padding:'32px 40px', width:'100%'}}>

      {/* Header */}
      <div style={{marginBottom:28}}>
        <h1 style={{fontFamily:"'Playfair Display',serif",fontSize:32,fontWeight:700,color:'var(--text)'}}>My Library</h1>
        <p style={{color:'var(--text-muted)',fontSize:14,marginTop:6}}>Your borrow history, requests and notifications</p>
      </div>

      {/* Tabs */}
      <div style={{display:'flex',gap:8,marginBottom:26,flexWrap:'wrap'}}>
        {tabs.map(t=>(
          <button key={t.key} onClick={()=>{ setTab(t.key); if(t.key==='trash') loadTrash(); }}
            style={{
              padding:'10px 20px',
              background: tab===t.key ? '#c9a84c' : 'var(--bg2)',
              color: tab===t.key ? '#1a1a2e' : 'var(--text-dim)',
              border: tab===t.key ? 'none' : '1px solid var(--border)',
              borderRadius:10, fontSize:13.5, fontWeight:700,
              fontFamily:'inherit', transition:'all .2s',
              display:'flex', alignItems:'center', gap:8,
              boxShadow: tab===t.key ? '0 4px 16px rgba(201,168,76,0.3)' : 'none',
              cursor:'pointer',
            }}>
            {t.label}
            {t.count>0 && (
              <span style={{
                background: tab===t.key ? '#1a1a2e' : '#c9a84c',
                color: tab===t.key ? '#c9a84c' : '#1a1a2e',
                borderRadius:99, padding:'1px 8px', fontSize:11, fontWeight:800
              }}>{t.count}</span>
            )}
          </button>
        ))}
      </div>

      {loading ? (
        <div style={{display:'flex',justifyContent:'center',padding:80}}>
          <div style={{width:32,height:32,border:'3px solid #c9a84c',borderTopColor:'transparent',borderRadius:'50%',animation:'spin 1s linear infinite'}}/>
        </div>
      ) : tab==='requests' ? (
        /* ── My Requests ── */
        requests.length ? (
          <div style={{display:'grid',gap:12}}>
            {requests.map(r=>{
              const st=statusStyle(r.status);
              return (
                <div key={r.id} className="hover-card"
                  style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:16,padding:'20px 22px',display:'flex',alignItems:'center',gap:20}}>
                  <div style={{width:10,height:10,borderRadius:'50%',background:st.color,flexShrink:0,boxShadow:`0 0 8px ${st.color}66`}}/>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:16,fontWeight:700,color:'var(--text)',marginBottom:4,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{r.title}</div>
                    <div style={{fontSize:13,color:'var(--text-dim)'}}>{r.author}</div>
                    <div style={{fontSize:12,color:'var(--text-muted)',marginTop:6}}>
                      Requested: {new Date(r.request_date).toLocaleDateString('en-GB',{day:'numeric',month:'short',year:'numeric'})}
                    </div>
                  </div>
                  <div style={{textAlign:'right',flexShrink:0}}>
                    <span style={{fontSize:12,fontWeight:700,padding:'5px 14px',borderRadius:99,background:st.bg,color:st.color,display:'inline-block',textTransform:'capitalize'}}>
                      {r.status}
                    </span>
                    {r.reject_reason && <div style={{fontSize:11,color:'#dc2626',marginTop:6,maxWidth:180}}>Reason: {r.reject_reason}</div>}
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div style={{textAlign:'center',padding:'80px 0'}}>
            <div style={{fontSize:14,color:'var(--text-muted)',fontStyle:'italic',marginBottom:8}}>No requests yet</div>
            <div style={{fontSize:13,color:'var(--text-muted)'}}>Go to Books page and click "Request Borrow"</div>
          </div>
        )
      ) : tab==='borrows' ? (
        /* ── Borrowed Books ── */
        borrows.length ? (
          <div style={{display:'grid',gap:12}}>
            {borrows.map(b=>{
              const st=statusStyle(b.status);
              return (
                <div key={b.id} className="hover-card"
                  style={{background:'var(--bg2)',border:`1px solid ${b.status==='overdue'?'rgba(239,68,68,0.3)':'var(--border)'}`,borderRadius:16,padding:'20px 22px',display:'flex',alignItems:'center',gap:20}}>
                  <div style={{width:10,height:10,borderRadius:'50%',background:st.color,flexShrink:0,boxShadow:`0 0 8px ${st.color}66`}}/>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:16,fontWeight:700,color:'var(--text)',marginBottom:4,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{b.title}</div>
                    <div style={{fontSize:13,color:'var(--text-dim)'}}>{b.author}</div>
                    <div style={{fontSize:12,color:'var(--text-muted)',marginTop:6}}>Due: {b.due_date?.split('T')[0]}</div>
                  </div>
                  <div style={{textAlign:'right',flexShrink:0}}>
                    <span style={{fontSize:12,fontWeight:700,padding:'5px 14px',borderRadius:99,background:st.bg,color:st.color,display:'inline-block',textTransform:'capitalize',marginBottom:b.fine_amount>0?6:0}}>{b.status}</span>
                    {b.fine_amount>0 && <div style={{fontSize:13,fontWeight:800,color:'#dc2626'}}>Fine: ৳{Number(b.fine_amount).toFixed(2)}</div>}
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div style={{textAlign:'center',padding:'80px 0',color:'var(--text-muted)',fontSize:14,fontStyle:'italic'}}>No books borrowed yet</div>
        )
      ) : tab==='notifications' ? (
        /* ── Notifications ── */
        <div>
          <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:16}}>
            <p style={{fontSize:13,color:'var(--text-muted)'}}>
              {notifs.length} notification{notifs.length!==1?'s':''}  · Delete করলে Trash এ যাবে (30 দিন)
            </p>
          </div>
          {notifs.length ? (
            <div style={{display:'grid',gap:12}}>
              {notifs.map(n=>(
                <div key={n.id} className="hover-card"
                  style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:16,padding:'18px 20px',display:'flex',alignItems:'flex-start',gap:16}}>
                  {/* Icon */}
                  <div style={{width:40,height:40,borderRadius:12,background:notifBg(n.type),border:`1px solid ${notifColor(n.type)}33`,display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0,fontSize:16,color:notifColor(n.type),fontWeight:800,boxShadow:`0 0 12px ${notifColor(n.type)}22`}}>
                    {notifIcon(n.type)}
                  </div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{display:'flex',alignItems:'center',gap:8,marginBottom:4}}>
                      <span style={{fontSize:12,fontWeight:700,padding:'2px 10px',borderRadius:99,background:notifBg(n.type),color:notifColor(n.type),textTransform:'capitalize'}}>
                        {n.type}
                      </span>
                      <span style={{fontSize:11,color:'var(--text-muted)',fontFamily:"'Space Mono',monospace"}}>
                        {new Date(n.created_at).toLocaleDateString('en-GB',{day:'numeric',month:'short',year:'numeric'})}
                      </span>
                    </div>
                    <div style={{fontSize:14,fontWeight:700,color:'var(--text)',marginBottom:4}}>{n.title}</div>
                    <div style={{fontSize:13,color:'var(--text-dim)',lineHeight:1.6}}>{n.message}</div>
                  </div>
                  {/* Delete → trash */}
                  <button onClick={()=>softDelete(n.id)}
                    title="Move to trash"
                    style={{flexShrink:0,width:32,height:32,borderRadius:8,background:'var(--bg3)',border:'1px solid var(--border)',color:'var(--text-muted)',cursor:'pointer',display:'flex',alignItems:'center',justifyContent:'center',fontSize:14,transition:'all .18s'}}
                    onMouseEnter={e=>{(e.currentTarget as HTMLButtonElement).style.background='rgba(239,68,68,0.1)';(e.currentTarget as HTMLButtonElement).style.color='#ef4444';(e.currentTarget as HTMLButtonElement).style.borderColor='rgba(239,68,68,0.2)';}}
                    onMouseLeave={e=>{(e.currentTarget as HTMLButtonElement).style.background='var(--bg3)';(e.currentTarget as HTMLButtonElement).style.color='var(--text-muted)';(e.currentTarget as HTMLButtonElement).style.borderColor='var(--border)';}}>
                    🗑
                  </button>
                </div>
              ))}
            </div>
          ) : (
            <div style={{textAlign:'center',padding:'80px 0'}}>
              <div style={{fontSize:32,marginBottom:12,opacity:.3}}>🔔</div>
              <div style={{fontSize:14,color:'var(--text-muted)',fontStyle:'italic'}}>No notifications</div>
            </div>
          )}
        </div>
      ) : (
        /* ── Trash ── */
        <div>
          <div style={{marginBottom:16}}>
            <p style={{fontSize:13,color:'var(--text-muted)'}}>
              Deleted notifications stay here for <strong style={{color:'var(--text-dim)'}}>30 days</strong>, then auto-delete permanently.
            </p>
          </div>
          {trash.length ? (
            <div style={{display:'grid',gap:12}}>
              {trash.map(n=>(
                <div key={n.id}
                  style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:16,padding:'18px 20px',display:'flex',alignItems:'flex-start',gap:16,opacity:.7}}>
                  <div style={{width:40,height:40,borderRadius:12,background:'var(--bg3)',border:'1px solid var(--border)',display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0,fontSize:16,color:'var(--text-muted)',fontWeight:800}}>
                    {notifIcon(n.type)}
                  </div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{display:'flex',alignItems:'center',gap:8,marginBottom:4}}>
                      <span style={{fontSize:12,fontWeight:700,padding:'2px 10px',borderRadius:99,background:'var(--bg3)',color:'var(--text-muted)',textTransform:'capitalize'}}>{n.type}</span>
                      <span style={{fontSize:11,color:'var(--text-muted)',fontFamily:"'Space Mono',monospace"}}>
                        {new Date(n.created_at).toLocaleDateString('en-GB',{day:'numeric',month:'short',year:'numeric'})}
                      </span>
                    </div>
                    <div style={{fontSize:14,fontWeight:600,color:'var(--text-dim)',marginBottom:4}}>{n.title}</div>
                    <div style={{fontSize:13,color:'var(--text-muted)',lineHeight:1.6}}>{n.message}</div>
                  </div>
                  {/* Permanent delete */}
                  <button onClick={()=>permDelete(n.id)}
                    title="Permanently delete"
                    style={{flexShrink:0,padding:'6px 12px',borderRadius:8,background:'rgba(239,68,68,0.08)',border:'1px solid rgba(239,68,68,0.15)',color:'#ef4444',cursor:'pointer',fontSize:11,fontWeight:700,fontFamily:'inherit',transition:'all .18s'}}
                    onMouseEnter={e=>{(e.currentTarget as HTMLButtonElement).style.background='rgba(239,68,68,0.18)';}}
                    onMouseLeave={e=>{(e.currentTarget as HTMLButtonElement).style.background='rgba(239,68,68,0.08)';}}>
                    Delete Forever
                  </button>
                </div>
              ))}
            </div>
          ) : (
            <div style={{textAlign:'center',padding:'80px 0'}}>
              <div style={{fontSize:32,marginBottom:12,opacity:.3}}>🗑️</div>
              <div style={{fontSize:14,color:'var(--text-muted)',fontStyle:'italic'}}>Trash is empty</div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}
